@Component({
  selector: 'app-table',
  templateUrl: './table.component.html',
})
export class TableComponent {
  rows = input.required<Customer[]>();
}

@Component({
  selector: 'app-filter-bar',
  template: '<input [formControl]="query" placeholder="Buscar" />',
})
export class FilterBarComponent {
  query = new FormControl('', { nonNullable: true });
}

@Component({
  template: '<app-table [rows]="customers()" />',
})
export class CustomersPage {
  customers = inject(CustomerService).list();
}

@Component({ templateUrl: './customer-detail.page.html' })
export class CustomerDetailPage {
  private route = inject(ActivatedRoute);
  customer = inject(CustomerService).find(this.route.snapshot.params['id']);
}

@Injectable({ providedIn: 'root' })
export class CustomerService {
  private http = inject(HttpClient);

  list() {
    return toSignal(this.http.get<Customer[]>('/api/customers'));
  }
}

@Injectable({ providedIn: 'root' })
export class ReportService {
  exportCustomers() {
    return this.http.get('/api/reports/customers.csv', { responseType: 'blob' });
  }
}

export type Customer = {
  id: string;
  name: string;
  status: 'active' | 'blocked';
};

export class CustomerStore {
  readonly selectedId = signal<string | null>(null);
  select(id: string) { this.selectedId.set(id); }
}
